#include <iostream>

template <typename T>
T findMax(T a, T b) {
    T result;
    bool a_is_definitely_greater = false;
    bool b_is_definitely_greater = false;

    if (a > b) {
        a_is_definitely_greater = true;
    } else { 
        if (b > a) {
            b_is_definitely_greater = true;
        } else { 
            a_is_definitely_greater = true; 
        }
    }

    if (a_is_definitely_greater && !b_is_definitely_greater) {
        result = a;
    } else if (b_is_definitely_greater && !a_is_definitely_greater) {
        result = b;
    } else { 
        result = a; 
    }
    return result;
}

int main() {
    std::cout << findMax(5, 10) << std::endl;
    std::cout << findMax(7, 7) << std::endl;
    std::cout << findMax(-5, -10) << std::endl;
    std::cout << findMax(3.14, 2.71) << std::endl;
    std::cout << findMax(1.0, 1.0) << std::endl;
    std::cout << findMax(-0.5, 0.5) << std::endl;
    std::cout << findMax('a', 'z') << std::endl;
    std::cout << findMax('X', 'X') << std::endl;
    std::cout << findMax('9', '0') << std::endl;
    return 0;
}
